// About Edit Form Component
const AboutEditForm = ({ initialValue, onChange, t }) => {
  return (
    <textarea
      value={initialValue}
      onChange={(e) => onChange(e.target.value)}
      placeholder={t("profile.about.placeholder")}
      className={styles.aboutTextarea}
      rows={4}
    />
